package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class TxnRecordCacheTest {

	@Test
	void recordCacheIteratorIsClosedWhenUpdateFromCacheFails(@TempDir File dataDir) throws Exception {
		TxnRecordCache recordCache = new TxnRecordCache(dataDir);
		TxnRecordCache.RecordCacheIterator iterator = null;
		try {
			assertTrue(recordCache.storeRecord(new long[] { 1, 2, 3, 4 }, true, false));
			recordCache.commit();

			iterator = recordCache.getRecords(true);
			assertTrue(iterator instanceof AutoCloseable,
					"Record cache iterators must support try-with-resources cleanup on replay failure");
		} finally {
			if (iterator != null) {
				iterator.close();
			}
			recordCache.close();
		}
	}
}
